10	/// Register local variable declarations from a block so they are visible to
11	/// returned_type() / get_type() lookups. This only declares variables (no
12	/// C code is generated).
13	fn declare_locals_from_block(cte: &mut CompileTimeEnv, block: &Expr) {
14	    match block {
15	        Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
16	            for expr in exprs {
17	                // Handle both bare Declare and Declare wrapped in Discard
18	                match expr.as_ref() {
19	                    Expr::Declare(name, var_type, expr_opt, is_mutable, _) => {
20	                        let ty = if let Some(vt) = var_type {
21	                            vt.clone()
22	                        } else if let Some(e) = expr_opt {
23	                            e.get_type(cte)
24	                        } else {
25	                            nil_type()
26	                        };
27	                        cte.declare_var(name.clone(), *is_mutable, ty);
28	                    }
29	                    Expr::Discard(inner) => {
30	                        if let Expr::Declare(name, var_type, expr_opt, is_mutable, _) =
31	                            inner.as_ref()
32	                        {
33	                            let ty = if let Some(vt) = var_type {
34	                                vt.clone()
35	                            } else if let Some(e) = expr_opt {
36	                                e.get_type(cte)
37	                            } else {
38	                                nil_type()
39	                            };
40	                            cte.declare_var(name.clone(), *is_mutable, ty);
41	                        }
42	                    }
43	                    _ => {}
44	                }
45	                // Recurse into nested blocks and function bodies
46	                declare_locals_from_block(cte, expr);
47	            }
48	        }
49	        Expr::Discard(inner) => declare_locals_from_block(cte, inner),
50	        _ => {}
51	    }
52	}
