54	impl Expr {
55	    pub fn to_c(&self, cte: &mut CompileTimeEnv, ctx: &mut CodeGenContext) -> bool {
56	        // if true - requires a semicolon at end of statement
57	        match self {
58	            Expr::Int(n) => {
59	                ctx.body.push_str(&n.to_string());
60	                false
61	            }
62	            Expr::Float(n) => {
63	                if n.fract() == 0.0 {
64	                    ctx.body.push_str(&n.to_string());
65	                    ctx.body.push_str(".0");
66	                } else {
67	                    ctx.body.push_str(&n.to_string());
68	                }
69	                false
70	            }
71	
72	            Expr::Bool(b) => {
73	                ctx.body.push_str(if *b { "true" } else { "false" });
74	                false
75	            }
76	            Expr::Char(c) => {
77	                ctx.body.push('\'');
78	                let c = c.chars().collect::<Vec<char>>()[0];
79	                match c {
80	                    '\n' => ctx.body.push_str("\\n"),
81	                    '\t' => ctx.body.push_str("\\t"),
82	                    '\0' => ctx.body.push_str("\\0"),
83	                    _ => ctx.body.push(c),
84	                }
85	                ctx.body.push('\'');
86	                false
87	            }
88	            Expr::Str(s) => {
89	                ctx.body.push('"');
90	                for c in s.chars() {
91	                    match c {
92	                        '\n' => ctx.body.push_str("\\n"),
93	                        '\t' => ctx.body.push_str("\\t"),
94	                        '\0' => ctx.body.push_str("\\0"),
95	                        _ => ctx.body.push(c),
96	                    }
97	                }
98	                ctx.body.push('"');
99	                false
100	            }
101	
102	            Expr::Add(l, r, span) => {
103	                let left_type = l.get_type(cte);
104	                let right_type = r.get_type(cte);
105	                if left_type.name() == "strlit" && right_type.name() == "char" {
106	                    // strlit + char: use dedicated strlit+char helper
107	                    ctx.body.push_str("v_1s_0Ct_6Ct_4CDD(");
108	                    l.to_c(cte, ctx);
109	                    ctx.body.push_str(",");
110	                    r.to_c(cte, ctx);
111	                    ctx.body.push_str(")");
112	                } else {
113	                    Expr::CallFunc(
114	                        "_add".into(),
115	                        vec![left_type],
116	                        vec![l.clone(), r.clone()],
117	                        *span,
118	                    )
119	                    .to_c(cte, ctx);
120	                }
121	                false
122	            }
123	
124	            Expr::Div(l, r, span) => {
125	                Expr::CallFunc(
126	                    "_div".into(),
127	                    vec![l.get_type(cte)],
128	                    vec![l.clone(), r.clone()],
129	                    *span,
130	                )
131	                .to_c(cte, ctx);
132	                false
133	            }
134	
135	            Expr::Less(l, r, span) => {
136	                Expr::CallFunc(
137	                    "_less".into(),
138	                    vec![l.get_type(cte)],
139	                    vec![l.clone(), r.clone()],
140	                    *span,
141	                )
142	                .to_c(cte, ctx);
143	                false
144	            }
145	
146	            Expr::Power(l, r, span) => {
147	                Expr::CallFunc(
148	                    "_pow".into(),
149	                    vec![l.get_type(cte)],
150	                    vec![l.clone(), r.clone()],
151	                    *span,
152	                )
153	                .to_c(cte, ctx);
154	                false
155	            }
156	            Expr::Sub(l, r, span) => {
157	                Expr::CallFunc(
158	                    "_sub".into(),
159	                    vec![l.get_type(cte)],
160	                    vec![l.clone(), r.clone()],
161	                    *span,
162	                )
163	                .to_c(cte, ctx);
164	                false
165	            }
166	            Expr::Mult(l, r, span) => {
167	                Expr::CallFunc(
168	                    "_mult".into(),
169	                    vec![l.get_type(cte)],
170	                    vec![l.clone(), r.clone()],
171	                    *span,
172	                )
173	                .to_c(cte, ctx);
174	                false
175	            }
176	            Expr::EqualEqual(l, r, span) => {
177	                Expr::CallFunc(
178	                    "_equal".into(),
179	                    vec![l.get_type(cte)],
180	                    vec![l.clone(), r.clone()],
181	                    *span,
182	                )
183	                .to_c(cte, ctx);
184	                false
185	            }
186	            Expr::Greater(l, r, span) => {
187	                Expr::CallFunc(
188	                    "_greater".into(),
189	                    vec![l.get_type(cte)],
190	                    vec![l.clone(), r.clone()],
191	                    *span,
192	                )
193	                .to_c(cte, ctx);
194	                false
195	            }
196	            Expr::GreaterEqual(l, r, span) => {
197	                Expr::CallFunc(
198	                    "_greater_equal".into(),
199	                    vec![l.get_type(cte)],
200	                    vec![l.clone(), r.clone()],
201	                    *span,
202	                )
203	                .to_c(cte, ctx);
204	                false
205	            }
206	
207	            Expr::LessEqual(l, r, span) => {
208	                Expr::CallFunc(
209	                    "_less_equal".into(),
210	                    vec![l.get_type(cte)],
211	                    vec![l.clone(), r.clone()],
212	                    *span,
213	                )
214	                .to_c(cte, ctx);
215	                false
216	            }
217	
218	            Expr::BangEqual(l, r, span) => {
219	                Expr::CallFunc(
220	                    "_bang_equal".into(),
221	                    vec![l.get_type(cte)],
222	                    vec![l.clone(), r.clone()],
223	                    *span,
224	                )
225	                .to_c(cte, ctx);
226	                false
227	            }
