229	            Expr::Not(expr, span) => {
230	                Expr::CallFunc("not".into(), vec![], vec![expr.clone()], *span).to_c(cte, ctx);
231	                false
232	            }
233	
234	            Expr::Or(l, r, span) => {
235	                Expr::CallFunc("or".into(), vec![], vec![l.clone(), r.clone()], *span)
236	                    .to_c(cte, ctx);
237	                false
238	            }
239	
240	            Expr::And(l, r, span) => {
241	                Expr::CallFunc("and".into(), vec![], vec![l.clone(), r.clone()], *span)
242	                    .to_c(cte, ctx);
243	                false
244	            }
245	
246	            Expr::StmtBlock(exprs, _span) => {
247	                for expr in exprs {
248	                    if expr.to_c(cte, ctx) {
249	                        ctx.body.push(';');
250	                    }
251	                    ctx.body.push('\n');
252	                }
253	                false
254	            }
255	
256	            Expr::If(if_cond, if_block, else_block, is_expr) => {
257	                if !is_expr {
258	                    ctx.body.push_str("if (");
259	                    if_cond.to_c(cte, ctx);
260	                    ctx.body.push_str(")");
261	                    if_block.to_c(cte, ctx);
262	                    if else_block.is_some() {
263	                        ctx.body.push_str(" else ");
264	                        else_block.clone().unwrap().to_c(cte, ctx);
265	                    }
266	                } else {
267	                    error(
268	                        if_cond.get_span(),
269	                        "EXPRESSION IF STATEMENTS NOT IMPLEMENTED",
270	                        "transpiling",
271	                    );
272	                }
273	
274	                let else_type = if let Some(ty) = else_block {
275	                    ty.get_type(cte)
276	                } else {
277	                    nil_type()
278	                };
279	                if if_block.get_type(cte) != else_type {
280	                    error(
281	                        if_block.get_span(),
282	                        "if and else blocks had different types",
283	                        "transpiling",
284	                    );
285	                }
286	
287	                false
288	            }
289	
290	            Expr::StmtBlockWithScope(exprs, span) => {
291	                cte.push_scope();
292	                ctx.body.push_str("{\n");
293	                Expr::StmtBlock(exprs.clone(), *span).to_c(cte, ctx);
294	                ctx.body.push('}');
295	                cte.pop_scope();
296	                false
297	            }
298	
299	            Expr::Print(expr, span) => {
300	                Expr::CallFunc(
301	                    "_print".into(),
302	                    vec![expr.get_type(cte)],
303	                    vec![expr.clone()],
304	                    *span,
305	                )
306	                .to_c(cte, ctx);
307	                true
308	            }
309	
310	            Expr::Discard(expr) => {
311	                expr.to_c(cte, ctx);
312	                true
313	            }
314	
315	            Expr::Variable(name, span) => {
316	                ctx.body.push_str(&cte.c_var_name(name, *span));
317	                false
318	            }
319	
320	            Expr::This(span) => {
321	                ctx.body.push(' ');
322	                ctx.body.push_str(&cte.c_var_name(cte.this(), *span));
323	                ctx.body.push(' ');
324	                false
325	            }
326	
327	            Expr::Declare(name, var_type, expr, is_mutable, span) => {
328	                let var_type = if var_type.is_some() {
329	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone().unwrap());
330	                    var_type.clone().unwrap()
331	                } else {
332	                    let t = expr.clone().unwrap().get_type(cte);
333	                    cte.declare_var(name.clone(), *is_mutable, t.clone());
334	                    t
335	                };
336	
337	                let var_type_name = cte.c_type_name(&var_type, ctx, *span);
338	                let var_name = cte.c_var_name(&name, *span);
339	                ctx.body += format!("{} {}", var_type_name, var_name).as_str();
340	
341	                if expr.is_some() {
342	                    ctx.body.push('=');
343	                    expr.clone().unwrap().to_c(cte, ctx);
344	                }
345	                true
346	            }
347	
348	            Expr::CallFunc(name, gens, exprs, span) => {
349	                if !cte.var_exists(name) {
350	                    error(
351	                        *span,
352	                        &format!("Function '{}' does not exist", name),
353	                        "transpiling",
354	                    );
355	                }
356	                ctx.body
357	                    .push_str(format!("{}(", cte.c_func_instance_name(name, gens, *span)).as_str());
358	                for expr in exprs.iter() {
359	                    // Check if this argument is a struct — if so, pass by pointer
360	                    let arg_type = expr.get_type(cte);
361	                    if cte.is_class(&arg_type) {
362	                        ctx.body.push_str("&");
363	                        expr.to_c(cte, ctx);
364	                    } else {
365	                        expr.to_c(cte, ctx);
366	                    }
367	                    ctx.body.push(',');
368	                }
369	                if exprs.len() >= 1 {
370	                    ctx.body.pop();
371	                }
372	
373	                ctx.body.push_str(")");
374	                true
375	            }
376	
377	            Expr::Stmt(expr) => {
378	                expr.to_c(cte, ctx);
379	                true
380	            }
381	
382	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
383	                let mut arg_types = vec![];
384	                for arg in args {
385	                    arg_types.push(arg.1.clone());
386	                }
387	
388	                // Push scope and declare parameters. Struct params use pointers in C.
389	                cte.push_scope();
390	                for arg in args {
391	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
392	                }
393	
394	                // Infer return type from return statements in the body.
395	                // Parameters are already declared in scope. We also need to declare
396	                // local variables from the body so they're resolvable.
397	                declare_locals_from_block(cte, block);
398	                let ret_type = block.returned_type(cte, *span);
399	                let return_type = if return_type.is_some() {
400	                    return_type.clone().unwrap()
401	                } else {
402	                    if let Some(ty) = ret_type.clone() {
403	                        ty
404	                    } else {
405	                        nil_type()
406	                    }
407	                };
408	
409	                let return_type_name = cte.c_type_name(&return_type, ctx, *span);
410	                let func_name = cte.c_func_instance_name(&name, &[], *span);
411	                ctx.body
412	                    .push_str(&format!("{} {}(", return_type_name, func_name));
413	
414	                let mut params: Vec<String> = Vec::new();
415	                for arg in args {
416	                    let param = cte.c_param_type(&arg.1, ctx, *span);
417	                    let var = cte.c_var_name(&arg.0, *span);
418	                    params.push(format!("{} {}", param, var));
419	                }
420	                ctx.body.push_str(&params.join(", "));
421	                if ctx.body.ends_with(", ") {
422	                    ctx.body.pop();
423	                    ctx.body.pop();
424	                }
425	
426	                ctx.body.push(')');
427	
428	                block.to_c(cte, ctx);
429	
430	                cte.pop_scope();
431	
432	                false
433	            }
434	
435	            Expr::Assign(left, right, span) => {
436	                match left.as_ref() {
437	                    Expr::Variable(name, _) => {
438	                        let var_info = cte.get_var(name).unwrap_or_else(|| {
439	                            error(
440	                                *span,
441	                                &format!("Could not find variable '{}'", name),
442	                                "transpiling",
443	                            );
444	                            (false, nil_type())
445	                        });
446	
447	                        cte.push_this(name);
448	
449	                        if var_info.1.name() == "ref" {
450	                            ctx.body.push_str("(*");
451	                            ctx.body.push_str(&cte.c_var_name(name, *span));
452	                            ctx.body.push(')');
453	                        } else {
454	                            ctx.body.push_str(&cte.c_var_name(name, *span));
455	                        }
456	
457	                        ctx.body.push('=');
458	                        right.to_c(cte, ctx);
459	                        cte.pop_this();
460	                    }
461	                    Expr::Member(expr, member, span) => {
462	                        let var_type = expr.get_type(cte);
463	
464	                        let member_type =
465	                            cte.get_member_type(&var_type, member).unwrap_or_else(|| {
466	                                error(
467	                                    *span,
468	                                    &format!("Could not find member '{}'", member),
469	                                    "transpiling",
470	                                );
471	                                nil_type()
472	                            });
473	
474	                        if member_type.name() == "ref" {
475	                            ctx.body.push_str("(*");
476	                        }
477	
478	                        expr.to_c(cte, ctx);
479	
480	                        if member_type.name() == "ref" {
481	                            ctx.body.push(')');
482	                        }
483	
484	                        ctx.body.push('.');
485	
486	                        ctx.body
487	                            .push_str(&cte.c_member_name(&var_type, member, *span));
488	
489	                        ctx.body.push('=');
490	                        right.to_c(cte, ctx);
491	                    }
492	                    _ => {
493	                        error(*span, "Invalid assignment target", "transpiler");
494	                    }
495	                }
496	                true
497	            }
498	
499	            Expr::Return(expr, _span) => {
500	                ctx.body.push_str("return ");
501	                expr.to_c(cte, ctx);
502	                true
503	            }
504	
505	            Expr::Delete(name) => {
506	                cte.del_var(name);
507	                false
508	            }
509	
510	            Expr::Nothing() => false,
511	
512	            Expr::While(cond, block) => {
513	                ctx.body.push_str("while (");
514	                cond.to_c(cte, ctx);
515	                ctx.body.push_str("){\n");
516	                block.to_c(cte, ctx);
517	                ctx.body.push_str("}");
518	                false
519	            }
520	
521	            Expr::Use { .. } => false,
522	
523	            Expr::Class(ty, members, span) => {
524	                let c_type_name = cte.c_type_name(ty, ctx, *span);
525	                ctx.types.push_str("struct ");
526	                ctx.types.push_str(&c_type_name);
527	                ctx.types.push_str(" {\n");
528	                let member_lines: Vec<String> = members
529	                    .iter()
530	                    .map(|(name, member_type)| {
531	                        let ty_name = cte.c_type_name(member_type, ctx, *span);
532	                        let m_name = cte.c_member_name(ty, name, *span);
533	                        format!("{} {}", ty_name, m_name)
534	                    })
535	                    .collect();
536	                ctx.types.push_str(&member_lines.join(";\n"));
537	                ctx.types.push_str(";\n");
538	                if ctx.types.ends_with("; \n") {
539	                    ctx.types.pop();
540	                    ctx.types.pop();
541	                    ctx.types.push('\n');
542	                }
543	                ctx.types.push_str("};\n");
544	
545	                true
546	            }
547	
548	            Expr::Member(expr, member, span) => {
549	                let var_type = expr.get_type(cte);
550	                expr.to_c(cte, ctx);
551	
552	                ctx.body.push('.');
553	
554	                ctx.body
555	                    .push_str(&cte.c_member_name(&var_type, member, *span));
556	                false
557	            }
558	
559	            Expr::Ref(expr, _span) => {
560	                ctx.body.push('&');
561	                expr.to_c(cte, ctx);
562	                false
563	            }
564	            Expr::Deref(expr, _span) => {
565	                ctx.body.push_str("(*");
566	                expr.to_c(cte, ctx);
567	                ctx.body.push(')');
568	                false
569	            }
570	
571	            Expr::Nth(left, right, _span) => {
572	                left.to_c(cte, ctx);
573	
574	                ctx.body.push('[');
575	                right.to_c(cte, ctx);
576	                ctx.body.push(']');
577	
578	                false
579	            }
580	
581	            _ => panic!("unexpected expression (for transpilation) '{:?}'", self),
582	        }
583	    }
