585	    pub fn pre_transpile(
586	        &self,
587	        cte: &mut CompileTimeEnv,
588	        ctx: &mut CodeGenContext,
589	        programs_to_transpile: &mut HashMap<String, bool>,
590	        current_file_dir: &str,
591	    ) {
592	        match self {
593	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
594	                if cte.get_var(name).is_some() {
595	                    error(
596	                    *span,
597	                    format!(
598	                        "Variable '{}' already exists and is immutable, could not declare function",
599	                        name
600	                    )
601	                        .as_str(),"pre-transpiling"
602	                );
603	                }
604	                let mut arg_types = vec![];
605	                for arg in args {
606	                    arg_types.push(arg.1.clone());
607	                }
608	
609	                // Push scope and declare parameters.
610	                cte.push_scope();
611	                for arg in args {
612	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
613	                }
614	
615	                // Process the body first so local variable declarations (like #x = ...)
616	                // are registered in the scope. This makes them visible to returned_type()
617	                // and get_type() calls that resolve variable names.
618	                block.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
619	
620	                let ret_type = block.returned_type(cte, *span);
621	                let return_type = if return_type.is_some() {
622	                    return_type.clone().unwrap()
623	                } else {
624	                    if let Some(ty) = ret_type.clone() {
625	                        ty
626	                    } else {
627	                        nil_type()
628	                    }
629	                };
630	
631	                cte.add_func_type(return_type.clone(), arg_types.clone(), ctx, *span);
632	                // Declare the variable first so c_func_instance_name can find it
633	                cte.declare_global_var(
634	                    name.clone(),
635	                    false,
636	                    Type::with_generics("func", {
637	                        arg_types.push(return_type.clone());
638	                        let output = arg_types;
639	                        output
640	                    }),
641	                );
642	
643	                let return_type_name = cte.c_type_name(&return_type, ctx, *span);
644	                let func_name = cte.c_func_instance_name(&name, &[], *span);
645	
646	                let mut decl_params: Vec<String> = Vec::new();
647	                for arg in args {
648	                    let param = cte.c_param_type(&arg.1, ctx, *span);
649	                    let var = cte.c_var_name(&arg.0, *span);
650	                    decl_params.push(format!("{} {}", param, var));
651	                }
652	                ctx.declarations
653	                    .push_str(&format!("{} {}(", return_type_name, func_name));
654	                ctx.declarations.push_str(&decl_params.join(", "));
655	                ctx.declarations.push_str(");\n");
656	
657	                cte.pop_scope();
658	            }
659	            Expr::Use { kind, path, span } => {
660	                let full_path = match kind {
661	                    UseKind::Std => format!("{}{}", STD_PATH, path),
662	                    UseKind::Normal => {
663	                        if current_file_dir.is_empty() {
664	                            path.to_string()
665	                        } else {
