741	    fn get_type(&self, cte: &mut CompileTimeEnv) -> Type {
742	        match self {
743	            Expr::Int(_) => "i32".into(),
744	            Expr::Float(_) => "f64".into(),
745	            Expr::Str(_) => "strlit".into(),
746	            Expr::Bool(_)
747	            | Expr::EqualEqual(..)
748	            | Expr::BangEqual(..)
749	            | Expr::Less(..)
750	            | Expr::LessEqual(..)
751	            | Expr::Greater(..)
752	            | Expr::GreaterEqual(..) => "bool".into(),
753	            Expr::Char(_) => "char".into(),
754	            Expr::Add(l, _, _)
755	            | Expr::Sub(l, ..)
756	            | Expr::Mult(l, ..)
757	            | Expr::Power(l, ..)
758	            | Expr::Div(l, ..) => l.get_type(cte),
759	            Expr::Return(_, _span) => nil_type(),
760	            Expr::Nth(..) => "char".into(),
761	            Expr::CallFunc(name, _, _, span) => {
762	                let function = cte
763	                    .get_var(name)
764	                    .unwrap_or_else(|| {
765	                        error(
766	                            *span,
767	                            &format!("Function not defined: {}", name),
768	                            "type checker",
769	                        );
770	                        (false, nil_type())
771	                    })
772	                    .1;
773	                function.generics().last().cloned().unwrap_or_else(nil_type)
774	            }
775	            Expr::StmtBlock(exprs, _span) => exprs.last().unwrap().get_type(cte),
776	            Expr::StmtBlockWithScope(exprs, _span) => exprs.last().unwrap().get_type(cte),
777	            Expr::Variable(name, span) => {
778	                cte.get_var(name)
779	                    .unwrap_or_else(|| {
780	                        error(
781	                            *span,
782	                            &format!("Variable not defined: {}", name),
783	                            "type checker",
784	                        );
785	                        (false, nil_type())
786	                    })
787	                    .1
788	            }
789	            Expr::Discard(..) => nil_type(),
790	            Expr::Print(expr, _) => expr.get_type(cte),
791	            Expr::If(_, block, ..) => block.get_type(cte),
792	            Expr::Member(expr, member_name, span) => {
793	                let var_type = expr.get_type(cte);
794	
795	                let member = cte.get_member_type(&var_type, member_name);
796	
797	                let member_type = if member.is_none() {
798	                    error(
799	                        *span,
800	                        &format!(
801	                            "Member '{}' not defined for type '{}'",
802	                            member_name, var_type
803	                        ),
804	                        "type checker",
805	                    );
806	                    nil_type()
807	                } else {
808	                    member.unwrap()
809	                };
810	
811	                member_type
812	            }
813	
814	            Expr::Ref(expr, _span) => {
815	                let expr_type = expr.get_type(cte);
816	                cte.register_type(expr_type.clone());
817	                Type::with_generics("ref", vec![expr_type])
818	            }
819	            Expr::Deref(expr, span) => {
820	                let expr_type = expr.get_type(cte);
821	                if expr_type.name() != "ref" {
822	                    error(*span, "Could not deref non-reference", "type checker");
823	                    return nil_type();
824	                }
825	                expr_type.generics()[0].clone()
826	            }
827	            _ => panic!("unexpected expression (for type check) '{:?}'", self),
828	        }
829	    }
